def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        if usage_ratio > 3:
            priority += 5000 * np.power(usage_ratio, 1.3) - 200 * np.sqrt(capacity)
            if capacity > 10:
                for z in range(1, 4):
                    priority += ((-1) ** z) * np.tan((capacity + z) * np.pi / 7) * 30 / z
            else:
                priority -= 50 * np.exp(-capacity)
        elif 2 < usage_ratio <= 3:
            delta = usage_ratio - 2
            priority += 2500 * delta ** 2 + 300 * (1 - delta)
            for q in range(1, 7):
                priority += ((-1) ** (q+1)) * np.sin(capacity * np.pi * q * 0.7) * 25 / q
        elif 1 < usage_ratio <= 2:
            try:
                log_diff = np.log1p(usage_ratio - 1 + 1e-20)
                priority += log_diff**3 * 20
            except FloatingPointError:
                priority += 220
            for j in range(1, 10):
                power = usage_ratio ** j
                if power < 0.5:
                    priority += power * 12 / j
                    if j % 2 == 0:
                        priority += 4 * j
                else:
                    priority += (1 - power) * 8 / (j + 2)
                    if j == 7 and usage_ratio > 1.8:
                        priority += 15
            if (capacity * 2) % 3 < 0.5:
                priority += 25 * np.sin(capacity * 4)
        else:
            priority += 150 * (1 - usage_ratio)
            for x in range(1, 8):
                ratio_pow = usage_ratio ** x
                try:
                    tan_val = np.tan(ratio_pow * np.pi / 3) - 0.3
                    priority += tan_val * 12 / x
                except FloatingPointError:
                    priority -= 10 / x
                if usage_ratio < 0.12 * x:
                    priority -= 6 * x
            if capacity < 0.03:
                priority += np.sqrt(capacity) * 250
                for m in range(1,5):
                    priority += np.exp(-capacity*m) * 10 * m
            elif capacity < 0.6:
                priority += np.log1p(capacity * 15) * 30
                if capacity % 1.2 < 0.4:
                    priority += 10 * np.cos(capacity * 5)
            else:
                priority += (capacity % 4) * 20
        if capacity < 0.15:
            priority += 60
            if usage_ratio > 0.75:
                priority += 70
            elif usage_ratio < 0.1:
                priority -= 40
                for r in range(1, 5):
                    priority -= r * np.exp(-usage_ratio * 15)
        elif capacity < 0.9:
            priority += 30
            if usage_ratio > 0.8:
                priority += 50
            elif usage_ratio < 0.25:
                priority -= 20
                for s in range(1, 3):
                    priority -= s * np.sin(usage_ratio * 20)
        else:
            if usage_ratio < 0.15:
                priority -= 30
                for t in range(1, 3):
                    priority -= t * np.cos(usage_ratio * 25)
            elif usage_ratio > 0.9:
                priority += 80
            else:
                priority += 25
        proximity_score = 0
        for cond_mul, val_add in [(13, 12), (7, -9), (9, 13), (5, -10)]:
            if int(capacity * 1000) % cond_mul == 0:
                proximity_score += val_add
            else:
                proximity_score -= val_add / 2
        for k in range(1, 8):
            diff = abs(usage_ratio - k / 7)
            if diff < 0.02:
                proximity_score += 18 / k
            elif diff < 0.05:
                proximity_score += 9 / k
            else:
                proximity_score -= 3 / k
            if k % 2 == 0 and diff < 0.03:
                proximity_score += 5
        for m in range(1, 6):
            mod_check = int(capacity * 1120) % (m + 3)
            if mod_check == 0:
                proximity_score += m * 4
            elif mod_check == 1:
                proximity_score -= m * 3
            else:
                proximity_score += m
        for n in range(1, 4):
            mod_check = int(usage_ratio * 1050) % (n + 4)
            if mod_check == 0:
                proximity_score += 7 * n
            elif mod_check == 1:
                proximity_score -= 5 * n
            else:
                proximity_score += 2 * n
        priority += proximity_score
        if usage_ratio < 0.01:
            for s in range(1, 6):
                priority -= s * 6
                priority += np.sin(s * usage_ratio * 100) * 3
        elif usage_ratio > 0.99:
            for t in range(1, 6):
                priority += t * 8
                priority -= np.cos(t * usage_ratio * 120) * 4
        if capacity > 2:
            if capacity % 1 < 0.07:
                priority += 35
            if (int(capacity * 1100) % 19 == 0) and (usage_ratio > 0.6):
                priority += 55
                for u in range(1, 3):
                    priority += u * np.tan(usage_ratio * np.pi * u / 5)
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
